class Solution:
    def reverseStr(self, s, k):
        chars = list(s)
        i = 0
        n = len(chars)
        while i < n:
            end = min(i + k, n)
            chars[i:end] = chars[i:end][::-1]
            i += 2 * k
        return ''.join(chars)

