var reverseStr = function(s, k) {
    let out = '';
    for (let i = 0; i < s.length; i += 2 * k) {
        const block = s.slice(i, i + 2 * k);
        const head = block.slice(0, k).split('').reverse().join('');
        out += head + block.slice(k);
    }
    return out;
};
